export declare const code = "/* Without allow-discrete, display:none would snap with no transition */\n.panel {\n  opacity: 1;\n  transform: translateY(0);\n  transition:\n    opacity   .35s ease,\n    transform .35s ease,\n    display   .35s allow-discrete;   /* Baseline 2024 */\n}\n\n.panel:not(.visible) {\n  display: none;       /* discrete \u2014 normally blocks transition */\n  opacity: 0;\n  transform: translateY(10px) scale(.96);\n}\n\n@starting-style {    /* entry transition start values */\n  .panel.visible { opacity: 0; transform: translateY(10px); }\n}";
export default function C2AllowDiscrete(): import("react/jsx-runtime").JSX.Element;
